};

export default KpiCard;

import React, { useState } from 'react';
import type { Business } from '../types';
import { Plan } from '../types';
import { initialBusinesses } from '../constants';
import ToggleSwitch from './ToggleSwitch';

const BusinessTable: React.FC = () => {
    const [businesses, setBusinesses] = useState<Business[]>(initialBusinesses);

    const handleToggle = (id: number) => {
        setBusinesses(prevBusinesses =>
            prevBusinesses.map(business =>
                business.id === id ? { ...business, isActive: !business.isActive } : business
            )
        );
    };

    const getPlanBadgeColor = (plan: Plan) => {
        switch (plan) {
            case Plan.BASICO:
                return 'bg-gray-500 text-gray-100';
            case Plan.PREMIUM:
                return 'bg-[#2c6b8f] text-white';
            case Plan.PRO:
                return 'bg-[#f06c44] text-white';
            default:
                return 'bg-gray-500';
        }
    };

    return (
        <div className="overflow-x-auto">
            <table className="min-w-full text-sm text-left text-slate-300">
                <thead className="text-xs text-slate-400 uppercase bg-slate-700/50">
                    <tr>
                        <th scope="col" className="px-6 py-3">Nombre del Negocio</th>
                        <th scope="col" className="px-6 py-3">Plan Asignado</th>
                        <th scope="col" className="px-6 py-3">Próximo Pago</th>
                        <th scope="col" className="px-6 py-3 text-center">Estado (Público)</th>
                    </tr>
                </thead>
                <tbody>
                    {businesses.map((business) => (
                        <tr key={business.id} className="bg-slate-800 border-b border-slate-700 hover:bg-slate-700/50">
                            <th scope="row" className="px-6 py-4 font-medium text-white whitespace-nowrap">
                                {business.name}
                            </th>
                            <td className="px-6 py-4">
                                <span className={`px-2 py-1 rounded-full text-xs font-semibold ${getPlanBadgeColor(business.plan)}`}>
                                    {business.plan}
                                </span>
                            </td>
                            <td className="px-6 py-4">
                                {new Date(business.paymentDate).toLocaleDateString('es-CL', { year: 'numeric', month: 'long', day: 'numeric' })}
                            </td>
                            <td className="px-6 py-4 text-center">
                                <ToggleSwitch
                                    checked={business.isActive}
                                    onChange={() => handleToggle(business.id)}
                                />
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default BusinessTable;

import React from 'react';

interface ToggleSwitchProps {
  checked: boolean;
  onChange: () => void;
}

const ToggleSwitch: React.FC<ToggleSwitchProps> = ({ checked, onChange }) => {
  return (
    <label htmlFor={`toggle-${Math.random()}`} className="flex items-center cursor-pointer justify-center">
      <div className="relative">
        <input
          type="checkbox"
          id={`toggle-${Math.random()}`}
          className="sr-only"
          checked={checked}
          onChange={onChange}
        />
        <div className={`block w-14 h-8 rounded-full transition ${checked ? 'bg-[#2c6b8f]' : 'bg-slate-600'}`}></div>
        <div
          className={`dot absolute left-1 top-1 bg-white w-6 h-6 rounded-full transition-transform transform ${
            checked ? 'translate-x-6' : 'translate-x-0'
          }`}
        ></div>
      </div>
    </label>
  );
};

export default ToggleSwitch;

import React from 'react';
import Sidebar from './components/Sidebar';
import KpiCard from './components/KpiCard';
import ManagementView from './components/ManagementView';
import { initialBusinesses, PLAN_PRICES } from './constants';
import type { Business } from './types';
import { Plan } from './types';

const App: React.FC = () => {

  // Calculate KPIs from mock data
  const totalLeads = initialBusinesses.reduce((sum, business) => sum + business.whatsappClicks, 0);
  const activeBusinessesCount = initialBusinesses.filter(b => b.isActive).length;
  const totalBusinesses = initialBusinesses.length;
  const projectedRevenue = initialBusinesses.reduce((sum, business) => {
    if (business.isActive) {
      return sum + (PLAN_PRICES[business.plan] || 0);
    }
    return sum;
  }, 0);
  const pendingPayments = initialBusinesses.filter(b => {
      const paymentDate = new Date(b.paymentDate);
      const today = new Date();
      // Simple logic: if payment date is in the past, it's pending.
      // A real app would use paymentStatus. This is for the KPI card.
      return paymentDate < today && b.isActive;
  }).length;


  const KpiChartIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 3.055A9.001 9.001 0 1020.945 13H11V3.055z" />
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.488 9H15V3.512A9.025 9.025 0 0120.488 9z" />
    </svg>
  );

  const UsersIcon = () => (
     <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.653-.125-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.653.125-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" />
    </svg>
  );

  const DollarIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v.01M12 6v-1h4a2 2 0 00-2-2H8a2 2 0 00-2 2h4v1M12 18V7m-3.79 4h7.58" />
    </svg>
  );

    const AlertIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
    </svg>
  );

  return (
    <div className="flex h-screen bg-slate-900 text-gray-200 font-sans">
      <Sidebar />
      <main className="flex-1 p-6 md:p-10 overflow-y-auto">
        <header>
          <h1 className="text-3xl font-bold text-white">Dashboard Principal</h1>
          <p className="text-slate-400 mt-1">Visión general del ecosistema TurismoTomé.</p>
        </header>

        <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mt-8">
          <KpiCard title="Total Leads (WhatsApp Clicks)" value={totalLeads.toString()} icon={<KpiChartIcon />} />
          <KpiCard title="Locales Activos" value={`${activeBusinessesCount}/${totalBusinesses}`} icon={<UsersIcon />} />
          <KpiCard title="Ingresos Proyectados Mes" value={`$${projectedRevenue.toLocaleString('es-CL')}`} icon={<DollarIcon />} />
          <KpiCard title="Pagos Pendientes" value={pendingPayments.toString()} icon={<AlertIcon />} color="orange" />
        </section>

        <section className="mt-10 bg-slate-800 rounded-lg shadow-lg p-6">
            <h2 className="text-xl font-bold text-white mb-4">Panel de Edición</h2>
            <ManagementView />
        </section>

      </main>
    </div>
  );
};

export default App;

