const BusinessForm: React.FC = () => {
    const [selectedBusinessId, setSelectedBusinessId] = useState<number>(initialBusinesses[0].id);
    const [business, setBusiness] = useState<Business | undefined>(undefined);

    useEffect(() => {
        const foundBusiness = initialBusinesses.find(b => b.id === selectedBusinessId);
        // Deep copy to prevent mutation of constant
        setBusiness(foundBusiness ? JSON.parse(JSON.stringify(foundBusiness)) : undefined);
    }, [selectedBusinessId]);

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        if (!business) return;
        const { name, value } = e.target;
