import React, { useState } from 'react';
import BusinessForm from './BusinessForm';
import BusinessList from './BusinessList';
import type { Business } from '../types';
import { initialBusinesses } from '../constants';

const NegociosView: React.FC = () => {
    const [businesses, setBusinesses] = useState<Business[]>(initialBusinesses);
    const [viewMode, setViewMode] = useState<'list' | 'form'>('list');
    const [selectedBusiness, setSelectedBusiness] = useState<Business | null>(null);

    const handleCreate = () => {
        setSelectedBusiness(null); 
        setViewMode('form');
    };

    const handleEdit = (business: Business) => {
        setSelectedBusiness(business);
        setViewMode('form');
    };

    const handleBackToList = () => {
        setViewMode('list');
        setSelectedBusiness(null);
    };

    const handleSave = (savedBusiness: Business) => {
        if (selectedBusiness) {
            // Edit existing
            setBusinesses(businesses.map(b => b.id === savedBusiness.id ? savedBusiness : b));
        } else {
            // Create new
            const newBusiness = { ...savedBusiness, id: Date.now(), whatsappClicks: 0 }; // Simple ID generation
            setBusinesses([...businesses, newBusiness]);
        }
        handleBackToList();
    };

    return (
        <>
            <header>
                <h1 className="text-3xl font-bold text-white">Gestión de Negocios</h1>
                <p className="text-slate-400 mt-1">
                    {viewMode === 'list' 
                        ? 'Visualiza, crea o edita los locales comerciales.'
                        : (selectedBusiness ? `Editando: ${selectedBusiness.name}` : 'Creando Nuevo Negocio')}
                </p>
            </header>
            <section className="mt-8 bg-slate-800 rounded-lg shadow-lg p-6">
                {viewMode === 'list' ? (
                    <BusinessList businesses={businesses} onCreate={handleCreate} onEdit={handleEdit} />
                ) : (
                    <BusinessForm business={selectedBusiness} onSave={handleSave} onCancel={handleBackToList} />
                )}
            </section>
        </>
    );
};

export default NegociosView;

import React, { useState, useEffect } from 'react';
import { Plan, Sector, PaymentStatus, Category } from '../types';
