                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </FormBlock>
            )}

            <FormBlock title="Asignación de Atributos Dinámicos">
                 <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                    {availableAttributes.map((attr) => (
                        <label key={attr.id} className="flex items-center space-x-3 bg-slate-700/50 p-3 rounded-lg cursor-pointer hover:bg-slate-700 transition-colors">
                            <input
                                type="checkbox"
                                checked={formData.serviceAttributes.includes(attr.name)}
