import { initialAttributes } from '../constants';

interface ServiceAttributesChecklistProps {
    category: Category;
    selectedAttributes: string[];
    onChange: (attributeName: string, isChecked: boolean) => void;
}

const ServiceAttributesChecklist: React.FC<ServiceAttributesChecklistProps> = ({ category, selectedAttributes, onChange }) => {
    const availableAttributes = initialAttributes.filter(attr => attr.categories.includes(category));

    return (
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
            {availableAttributes.map((attr) => (
                <label key={attr.id} className="flex items-center space-x-3 bg-slate-700/50 p-3 rounded-lg cursor-pointer hover:bg-slate-700 transition-colors">
                    <input
                        type="checkbox"
                        checked={selectedAttributes.includes(attr.name)}
                        onChange={(e) => onChange(attr.name, e.target.checked)}
                        className="h-5 w-5 rounded bg-slate-600 border-slate-500 text-[#2c6b8f] focus:ring-2 focus:ring-offset-0 focus:ring-offset-slate-800 focus:ring-[#2c6b8f]"
                    />
                    <span className="text-white font-medium">{attr.name}</span>
                </label>
            ))}
        </div>
    );
};

export default ServiceAttributesChecklist;

import React, { useState, useEffect } from 'react';
import { Plan, Sector, PaymentStatus, Category } from '../types';
import type { Business, Specialty, DaySchedule } from '../types';
import ImageUpload from './ImageUpload';
import ToggleSwitch from './ToggleSwitch';
import BusinessHoursEditor from './BusinessHoursEditor';
import ServiceAttributesChecklist from './ServiceAttributesChecklist';

interface BusinessFormProps {
    business: Business | null;
    onSave: (business: Business) => void;
    onCancel: () => void;
}

const NEW_BUSINESS_TEMPLATE: Omit<Business, 'id' | 'whatsappClicks'> = {
    ownerName: '',
    privateContactNumber: '',
    email: '',
    adminName: '',
    adminPhoneNumber: '',
    plan: Plan.BASICO,
    category: Category.RESTAURANTE,
    name: '',
    whatsappNumber: '',
    phoneNumber: '',
    googleMapsLink: '',
    hours: [
        { day: 'Lunes', opens: '09:00', closes: '20:00', closed: false },
        { day: 'Martes', opens: '09:00', closes: '20:00', closed: false },
        { day: 'Miércoles', opens: '09:00', closes: '20:00', closed: false },
        { day: 'Jueves', opens: '09:00', closes: '20:00', closed: false },
        { day: 'Viernes', opens: '09:00', closes: '22:00', closed: false },
        { day: 'Sábado', opens: '10:00', closes: '22:00', closed: false },
        { day: 'Domingo', opens: '', closes: '', closed: true },
    ],
    serviceAttributes: [],
    digitalMenuLink: '',
    heroImage: '',
    galleryImages: ['', '', '', ''],
    specialties: [
        { photo: '', name: '', description: '', price: '0', showPrice: true },
        { photo: '', name: '', description: '', price: '0', showPrice: true },
        { photo: '', name: '', description: '', price: '0', showPrice: true },
    ],
    shortDescription: '',
    longDescription: '',
    sector: Sector.EL_MORRO,
    paymentDate: new Date().toISOString().split('T')[0],
    paymentStatus: PaymentStatus.PENDIENTE,
    isActive: true,
};


const BusinessForm: React.FC<BusinessFormProps> = ({ business, onSave, onCancel }) => {
    const [formData, setFormData] = useState<Omit<Business, 'id' | 'whatsappClicks'>>(() => 
        business ? JSON.parse(JSON.stringify(business)) : NEW_BUSINESS_TEMPLATE
    );

    useEffect(() => {
        setFormData(business ? JSON.parse(JSON.stringify(business)) : NEW_BUSINESS_TEMPLATE);
    }, [business]);

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSpecialtyChange = (index: number, field: keyof Specialty, value: string | boolean) => {
        const updatedSpecialties = [...formData.specialties];
        (updatedSpecialties[index] as any)[field] = value;
        setFormData(prev => ({ ...prev, specialties: updatedSpecialties }));
    };

     const handleHoursChange = (dayIndex: number, field: keyof DaySchedule, value: string | boolean) => {
        const updatedHours = [...formData.hours];
        (updatedHours[dayIndex] as any)[field] = value;
        setFormData(prev => ({ ...prev, hours: updatedHours }));
    };

    const handleAttributeChange = (attributeName: string, isChecked: boolean) => {
        setFormData(prev => {
            const currentAttributes = prev.serviceAttributes || [];
            if (isChecked) {
                // Add attribute if not already present
                return { ...prev, serviceAttributes: [...new Set([...currentAttributes, attributeName])] };
            } else {
                // Remove attribute
                return { ...prev, serviceAttributes: currentAttributes.filter(attr => attr !== attributeName) };
            }
        });
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSave({ ...formData, id: business?.id || 0, whatsappClicks: business?.whatsappClicks || 0 });
    }

    const FormLabel: React.FC<{ children: React.ReactNode }> = ({ children }) => (
        <label className="block text-sm font-bold text-[#2c6b8f] mb-2">{children}</label>
    );

    const FormInput = (props: React.InputHTMLAttributes<HTMLInputElement>) => (
        <input {...props} className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-[#2c6b8f]" />
    );

    const FormSelect = (props: React.SelectHTMLAttributes<HTMLSelectElement>) => (
         <select {...props} className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 text-white focus:outline-none focus:ring-2 focus:ring-[#2c6b8f]" />
    );

    const FormBlock: React.FC<{ title: string; children: React.ReactNode }> = ({ title, children }) => (
        <div className="space-y-6 bg-slate-800/50 p-6 rounded-lg w-full block relative">
            <h3 className="text-lg font-semibold text-white border-b border-slate-700 pb-2 mb-6">{title}</h3>
            {children}
        </div>
    );

    return (
        <form onSubmit={handleSubmit} className="flex flex-col space-y-12">
            <FormBlock title="Gestión Administrativa (Privado)">
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    <div>
                        <FormLabel>Nombre del Dueño</FormLabel>
                        <FormInput name="ownerName" value={formData.ownerName} onChange={handleInputChange} required />
                    </div>
                    <div>
                        <FormLabel>Contacto Privado</FormLabel>
                        <FormInput name="privateContactNumber" type="tel" value={formData.privateContactNumber} onChange={handleInputChange} />
                    </div>
                     <div>
                        <FormLabel>Email</FormLabel>
                        <FormInput name="email" type="email" value={formData.email} onChange={handleInputChange} />
                    </div>
                    <div>
                        <FormLabel>Administrador</FormLabel>
                        <FormInput name="adminName" value={formData.adminName} onChange={handleInputChange} />
                    </div>
                    <div>
                        <FormLabel>Teléfono Admin</FormLabel>
                        <FormInput name="adminPhoneNumber" type="tel" value={formData.adminPhoneNumber} onChange={handleInputChange} />
                    </div>
                    <div>
                        <FormLabel>Selector de Plan</FormLabel>
                        <FormSelect name="plan" value={formData.plan} onChange={handleInputChange}>
                            {Object.values(Plan).map(p => <option key={p} value={p}>{p}</option>)}
                        </FormSelect>
                    </div>
                </div>
            </FormBlock>

            <FormBlock title="Información Pública">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                        <FormLabel>Categoría</FormLabel>
                        <FormSelect name="category" value={formData.category} onChange={handleInputChange}>
                            {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
                        </FormSelect>
                    </div>
                     <div>
                        <FormLabel>Nombre del Local</FormLabel>
                        <FormInput name="name" value={formData.name} onChange={handleInputChange} required />
                    </div>
                     <div>
                        <FormLabel>WhatsApp (Link)</FormLabel>
                        <div className="flex gap-2">
                            <FormInput name="whatsappNumber" placeholder="+569..." type="tel" value={formData.whatsappNumber} onChange={handleInputChange} />
                            <a href={`https://wa.me/${formData.whatsappNumber}`} target="_blank" rel="noopener noreferrer" className="bg-green-600 text-white font-bold p-2 rounded-lg flex items-center justify-center hover:bg-green-500 transition-colors duration-200">✓</a>
                        </div>
                    </div>
                    <div>
                        <FormLabel>Botón de Llamada Telefónica</FormLabel>
                        <div className="flex gap-2">
                            <FormInput name="phoneNumber" type="tel" value={formData.phoneNumber} onChange={handleInputChange} />
                            <a href={`tel:${formData.phoneNumber}`} target="_blank" rel="noopener noreferrer" className="bg-slate-600 text-white font-bold p-2 rounded-lg flex items-center justify-center hover:bg-slate-500 transition-colors duration-200">📞</a>
                        </div>
                    </div>
                    <div className="md:col-span-2">
                        <FormLabel>Enlace Google Maps</FormLabel>
                        <FormInput name="googleMapsLink" type="url" value={formData.googleMapsLink} onChange={handleInputChange} />
                    </div>
                </div>
            </FormBlock>

            <FormBlock title="Horarios (Estilo Google My Business)">
                <BusinessHoursEditor hours={formData.hours} onChange={handleHoursChange} />
            </FormBlock>

            {formData.category === Category.RESTAURANTE && (
                <div className="w-full block">
                    <FormBlock title="Solo para 'Restaurante'">
                         <div>
                            <FormLabel>Hipervínculo a la Carta Digital</FormLabel>
                            <FormInput name="digitalMenuLink" type="url" value={formData.digitalMenuLink} onChange={handleInputChange} />
                        </div>
                        <h4 className="text-md font-semibold text-white pt-4">Especialidades</h4>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                            {formData.specialties.map((specialty, index) => (
                                <div key={index} className="bg-slate-900/50 p-4 rounded-lg space-y-4 min-h-max">
                                    <ImageUpload label={`Foto Plato ${index + 1}`} />
                                    <FormInput placeholder="Nombre del Plato" value={specialty.name} onChange={(e) => handleSpecialtyChange(index, 'name', e.target.value)} />
                                    <textarea placeholder="Descripción del producto" rows={3} value={specialty.description} onChange={(e) => handleSpecialtyChange(index, 'description', e.target.value)} className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-[#2c6b8f]" />
                                    <div>
                                        <FormInput placeholder="Precio" type="number" value={specialty.price} onChange={(e) => handleSpecialtyChange(index, 'price', e.target.value)} />
                                        <div className="flex items-center space-x-2 mt-2">
                                            <ToggleSwitch checked={specialty.showPrice} onChange={() => handleSpecialtyChange(index, 'showPrice', !specialty.showPrice)} />
                                            <span className="text-xs text-slate-400">Activar/Desactivar precio</span>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </FormBlock>
                </div>
            )}

            <FormBlock title="Asignación de Atributos Dinámicos">
                 <ServiceAttributesChecklist
                    category={formData.category}
                    selectedAttributes={formData.serviceAttributes}
                    onChange={handleAttributeChange}
                 />
            </FormBlock>

            <FormBlock title="Gestor de Medios (Al Final)">
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                    <ImageUpload label="Upload Hero Plate" />
                    <div className="space-y-4">
                        <p className="block text-sm font-bold text-[#2c6b8f]">Galería (4 fotos)</p>
                        <div className="grid grid-cols-2 gap-4">
                            <ImageUpload label="Imagen 1" />
                            <ImageUpload label="Imagen 2" />
                            <ImageUpload label="Imagen 3" />
                            <ImageUpload label="Imagen 4" />
                        </div>
                    </div>
                </div>
            </FormBlock>

            <div className="flex justify-end pt-4 space-x-3">
                 <button type="button" onClick={onCancel} className="bg-slate-600 text-white font-bold py-2 px-6 rounded-lg hover:bg-slate-500 transition-colors duration-200">
                    Cancelar
                </button>
                <button type="submit" className="bg-[#f06c44] text-white font-bold py-2 px-6 rounded-lg hover:bg-orange-600 transition-colors duration-200">
                    Guardar Cambios
                </button>
            </div>
        </form>
    );
};

export default BusinessForm;

import React from 'react';
import type { Category } from '../types';
import { initialAttributes } from '../constants';

interface ServiceAttributesChecklistProps {
  category: Category;
  selectedAttributes: string[];
  onChange: (attributeName: string, isChecked: boolean) => void;
}

const ServiceAttributesChecklist: React.FC<ServiceAttributesChecklistProps> = ({ 
  category, 
  selectedAttributes, 
  onChange 
}) => {
  const availableAttributes = initialAttributes.filter(attr => 
    attr.categories.includes(category)
  );

  return (
      <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
        {availableAttributes.map((attr) => (
          <label key={attr.id} className="flex items-center space-x-3 bg-slate-700/50 p-3 rounded-lg cursor-pointer hover:bg-slate-700 transition-colors">
            <input
              type="checkbox"
              checked={selectedAttributes.includes(attr.name)}
              onChange={(e) => onChange(attr.name, e.target.checked)}
              className="h-5 w-5 rounded bg-slate-600 border-slate-500 text-[#2c6b8f] focus:ring-2 focus:ring-offset-0 focus:ring-offset-slate-800 focus:ring-[#2c6b8f]"
            />
            <span className="text-white font-medium text-sm">{attr.name}</span>
          </label>
        ))}
      </div>
  );
};

export default ServiceAttributesChecklist;

