                <div className={`transition-all duration-500 ease-in-out overflow-hidden ${formData.hasPromotionsActive ? 'max-h-[1000px] mt-8' : 'max-h-0'}`}>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-stretch">
                        {formData.promotions?.map((promo: any, index: number) => (
