                                <input placeholder="Título de la Promoción" className="w-full bg-slate-800 p-3 rounded-lg text-white text-sm" value={promo.name} onChange={(e) => handlePromotionChange(index, 'name', e.target.value)} />
                                <textarea placeholder="Descripción de la oferta..." rows={4} className="w-full bg-slate-800 p-3 rounded-lg text-white text-sm" value={promo.description} onChange={(e) => handlePromotionChange(index, 'description', e.target.value)} />
