}

export enum PaymentStatus {
  AL_DIA = 'Al día',
  PENDIENTE = 'Pendiente',
}

export enum Category {
  RESTAURANTE = 'Restaurante',
  ALOJAMIENTO = 'Alojamiento',
  COMERCIO = 'Comercio',
  PANORAMA = 'Panorama',
}

export interface Specialty {
  photo: string; // URL or placeholder
  name: string;
  description: string;
  price: string;
  showPrice: boolean;
}

export interface Promotion {
  photo: string;
  name: string;
  description: string;
  normalPrice?: string;
