                            <h4 className="text-md font-bold text-slate-300 mb-4 border-b border-slate-700 pb-2">Capacidad y Tipos de Unidad</h4>
                            <div className="space-y-4 mt-4">
                                {(formData.unitTypes || []).map((unit: any, index: number) => (
