                                ))}
                            </div>
                        </div>
                    </div>
                </FormBlock>
            )}

            <FormBlock title="Gestión de Promociones y Ofertas">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-stretch">
                    {(formData.promotions || []).map((promo: Promotion, index: number) => (
                        <div key={index} className="flex flex-col bg-slate-900 p-5 rounded-xl border border-slate-700 space-y-4 shadow-2xl min-h-fit">
                            <ImageUpload label={`Imagen Promo ${index + 1} (1:1)`} />
                            <input placeholder="Título de la Promoción" className="w-full bg-slate-800 p-3 rounded-lg text-white text-sm" value={promo.name} onChange={(e) => handlePromotionChange(index, 'name', e.target.value)} />
                            <textarea placeholder="Descripción de la oferta..." rows={3} className="w-full bg-slate-800 p-3 rounded-lg text-white text-sm" value={promo.description} onChange={(e) => handlePromotionChange(index, 'description', e.target.value)} />

                            <div className="flex gap-4 pt-4 border-t border-slate-800">
                                <div>
                                    <label className="text-xs font-bold text-slate-400">Precio Antes</label>
                                    <input type="number" placeholder="$" className="w-full bg-slate-800 p-2 rounded-lg text-slate-400 line-through" value={promo.normalPrice || ''} onChange={(e) => handlePromotionChange(index, 'normalPrice', e.target.value)} />
                                </div>
                                <div>
                                     <label className="text-xs font-bold text-[#f06c44]">Precio Ahora</label>
                                    <input type="number" placeholder="$" className="w-full bg-slate-800 p-2 rounded-lg text-white font-bold border border-[#f06c44]/50 focus:ring-[#f06c44] focus:border-[#f06c44]" value={promo.offerPrice || ''} onChange={(e) => handlePromotionChange(index, 'offerPrice', e.target.value)} />
                                </div>
                            </div>

                            {formData.category !== Category.RESTAURANTE && (
                                <button type="button" className="mt-2 w-full bg-green-600 text-white font-bold py-3 px-4 rounded-lg hover:bg-green-700 transition-colors flex items-center justify-center text-sm">
                                    <WhatsAppIcon />
                                    {getPromotionButtonText()}
                                </button>
                            )}
                        </div>
                    ))}
                </div>
            </FormBlock>

            <div className="w-full py-4">
                <ServiceAttributesChecklist 
                    category={formData.category} 
                    selectedAttributes={formData.serviceAttributes || []} 
                    onChange={handleAttributeChange} 
                />
            </div>

            <FormBlock title="Gestor de Medios (Hero y Galería)">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <ImageUpload label="Hero Image" />
                    <div className="grid grid-cols-2 gap-3">
                        <ImageUpload label="G1" /> <ImageUpload label="G2" />
                        <ImageUpload label="G3" /> <ImageUpload label="G4" />
                    </div>
                </div>
            </FormBlock>

            <div className="sticky bottom-6 flex justify-end space-x-4 bg-slate-900/90 backdrop-blur-md p-6 rounded-2xl border border-slate-700 shadow-2xl z-50">
                <button type="button" onClick={onCancel} className="px-10 py-4 bg-slate-700 text-white rounded-xl font-black">CANCELAR</button>
                <button type="submit" className="px-10 py-4 bg-[#f06c44] text-white rounded-xl font-black">GUARDAR CAMBIOS</button>
            </div>
        </form>
    );
};

export default BusinessForm;

