  ALOJAMIENTO = 'Alojamiento',
  COMERCIO = 'Comercio',
  PANORAMA = 'Panorama',
}

export interface Specialty {
  photo: string; // URL or placeholder
  name: string;
  description: string;
  price: string;
  showPrice: boolean;
}

export interface Promotion {
  id: string;
  title: string;
  normalPrice: number;
  promoPrice: number;
  image: string;
  isActive: boolean;
  isFeatured: boolean;
}

export interface DaySchedule {
  day: string;
  opens: string;
  closes: string;
  closed: boolean;
}

export interface Attribute {
  id: number;
  name: string;
  categories: Category[];
}

export interface UnitType {
  name: string;
  capacity: string;
}

export interface Business {
  id: number;
  // Bloque 1: Gestión Administrativa
  ownerName: string;
  privateContactNumber: string;
  email: string;
  adminName: string;
  adminPhoneNumber: string;
  plan: Plan;

  // Bloque 2: Información para la Web
  category: Category;
  name: string; // Nombre del Local (Público)
  whatsappNumber: string;
  phoneNumber: string; // Para llamadas directas
  googleMapsLink: string;

  // Bloque 3: Horarios
  hours: DaySchedule[];

  // Bloque 4: Lógica Especial (Restaurante)
  digitalMenuLink?: string;
  specialties?: Specialty[];

  // Bloque 4.5: Lógica Especial (Alojamiento)
  checkIn?: string;
  checkOut?: string;
  unitTypes?: UnitType[];

  // Bloque 5: Atributos
  serviceAttributes: string[];

  // Bloque 6: Medios
  heroImage: string; // URL or placeholder
  galleryImages: string[]; // Array of URLs or placeholders

  // Bloque 7: Promociones
  hasPromotionsActive?: boolean;
  promotions?: Promotion[];

  // Campos existentes
  shortDescription: string;
  longDescription: string;
  sector: Sector;
  paymentDate: string;
  paymentStatus: PaymentStatus;
  isActive: boolean;
  whatsappClicks: number;
}

export interface SectorData {
  id: Sector;
  name: string;
  heroTitle: string;
  backgroundImage: string;
}

