    const [filterSector, setFilterSector] = useState('');

    const handleToggle = (promoId: string, field: 'isActive' | 'isFeatured') => {
        setPromotions(currentPromos => 
            currentPromos.map(p => 
                p.id === promoId ? { ...p, [field]: !p[field] } : p
            )
        );
