                                </div>
                                <div>
                                     <label className="text-xs font-bold text-[#f06c44]">Precio Ahora</label>
                                    <input type="number" placeholder="$" className="w-full bg-slate-800 p-2 rounded-lg text-white font-bold border border-[#f06c44]/50 focus:ring-[#f06c44] focus:border-[#f06c44]" value={promo.promoPrice || ''} onChange={(e) => handlePromotionChange(index, 'promoPrice', parseInt(e.target.value, 10) || 0)} />
                                </div>
