import React, { useState, useMemo } from 'react';
import type { CulturalEvent, Business } from '../types';
import { Sector } from '../types';
import ImageUpload from './ImageUpload';

interface CulturalEventFormProps {
    event: CulturalEvent | null;
    allBusinesses: Business[];
    onSave: (event: CulturalEvent) => void;
    onCancel: () => void;
}

const NEW_EVENT_TEMPLATE: Omit<CulturalEvent, 'id'> = {
    name: '',
    location: Sector.EL_MORRO,
    startDate: new Date().toISOString().split('T')[0],
    endDate: new Date().toISOString().split('T')[0],
    linkedBusinesses: [],
    promoBannerUrl: '',
};

const CulturalEventForm: React.FC<CulturalEventFormProps> = ({ event, allBusinesses, onSave, onCancel }) => {
    const [formData, setFormData] = useState<Omit<CulturalEvent, 'id'>>(() => 
        event ? { ...event } : { ...NEW_EVENT_TEMPLATE }
    );

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleBusinessLinkToggle = (businessId: number) => {
        setFormData(prev => {
            const linked = prev.linkedBusinesses;
            const isLinked = linked.includes(businessId);
            return {
                ...prev,
                linkedBusinesses: isLinked 
                    ? linked.filter(id => id !== businessId)
                    : [...linked, businessId],
            };
        });
    };

    const businessesBySector = useMemo(() => {
        return allBusinesses.reduce((acc, business) => {
            (acc[business.sector] = acc[business.sector] || []).push(business);
            return acc;
        }, {} as Record<Sector, Business[]>);
    }, [allBusinesses]);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSave({ ...formData, id: event?.id || Date.now() });
    };

    return (
        <form onSubmit={handleSubmit} className="bg-slate-800 rounded-lg shadow-lg p-6 space-y-6">
            <h2 className="text-xl font-bold text-white border-b border-slate-700 pb-3">
                {event ? `Editando: ${event.name}` : 'Crear Nuevo Evento Cultural'}
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <label className="block text-sm font-bold text-[#2c6b8f] mb-2">Nombre de la Fiesta</label>
                    <input 
                        name="name" 
                        value={formData.name} 
                        onChange={handleInputChange}
                        className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 text-white"
                        required
                    />
                </div>
                <div>
                    <label className="block text-sm font-bold text-[#2c6b8f] mb-2">Localidad</label>
                    <select
                        name="location"
                        value={formData.location}
                        onChange={handleInputChange}
                        className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 text-white"
                    >
                       {Object.values(Sector).map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                </div>
                <div>
                    <label className="block text-sm font-bold text-[#2c6b8f] mb-2">Fecha de Inicio</label>
                    <input 
                        type="date"
                        name="startDate" 
                        value={formData.startDate} 
                        onChange={handleInputChange}
                        className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 text-white"
                        required
                    />
                </div>
                 <div>
                    <label className="block text-sm font-bold text-[#2c6b8f] mb-2">Fecha de Término</label>
                    <input 
                        type="date"
                        name="endDate" 
                        value={formData.endDate} 
                        onChange={handleInputChange}
                        className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 text-white"
                        required
                    />
                </div>
            </div>

            <div>
                <label className="block text-sm font-bold text-[#f06c44] mb-2">Banner Promocional / Afiche</label>
                <ImageUpload label="Arrastra o selecciona el afiche del evento" />
            </div>

            <div>
                <label className="block text-sm font-bold text-[#2c6b8f] mb-2">Negocios Vinculados</label>
                <div className="bg-slate-900/50 p-4 rounded-lg border border-slate-700 max-h-64 overflow-y-auto space-y-4">
                    {Object.entries(businessesBySector).map(([sector, businesses]) => (
                        <div key={sector}>
                            <h4 className="font-bold text-slate-300 border-b border-slate-600 pb-1 mb-2">{sector}</h4>
                            <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
                                {/* FIX: Explicitly cast `businesses` to `Business[]` to resolve a TypeScript type inference issue. */}
                                {(businesses as Business[]).map(business => (
                                    <label key={business.id} className="flex items-center space-x-2 bg-slate-700/50 p-2 rounded-md cursor-pointer hover:bg-slate-700">
                                        <input
                                            type="checkbox"
                                            checked={formData.linkedBusinesses.includes(business.id)}
                                            onChange={() => handleBusinessLinkToggle(business.id)}
                                            className="h-4 w-4 rounded bg-slate-600 border-slate-500 text-[#2c6b8f] focus:ring-0"
                                        />
                                        <span className="text-white text-sm">{business.name}</span>
                                    </label>
                                ))}
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="flex justify-end pt-4 space-x-3 border-t border-slate-700">
                 <button type="button" onClick={onCancel} className="bg-slate-600 text-white font-bold py-2 px-6 rounded-lg hover:bg-slate-500 transition-colors duration-200">
                    Cancelar
                </button>
                <button type="submit" className="bg-[#f06c44] text-white font-bold py-2 px-6 rounded-lg hover:bg-orange-600 transition-colors duration-200">
                    Guardar Evento
                </button>
            </div>
        </form>
    );
};

export default CulturalEventForm;

import React, { useState } from 'react';
import BusinessForm from './BusinessForm';
import BusinessList from './BusinessList';
import BusinessPublicView from './BusinessPublicView';
import type { Business } from '../types';
import { initialBusinesses } from '../constants';

const NegociosView: React.FC = () => {
    const [businesses, setBusinesses] = useState<Business[]>(initialBusinesses);
    const [viewMode, setViewMode] = useState<'list' | 'form' | 'publicView'>('list');
    const [selectedBusiness, setSelectedBusiness] = useState<Business | null>(null);

    const handleCreate = () => {
        setSelectedBusiness(null); 
        setViewMode('form');
    };

    const handleEdit = (business: Business) => {
        setSelectedBusiness(business);
        setViewMode('form');
    };

    const handleViewPublic = (business: Business) => {
        setSelectedBusiness(business);
        setViewMode('publicView');
    };

    const handleBackToList = () => {
        setViewMode('list');
        setSelectedBusiness(null);
    };

    const handleSave = (savedBusiness: Business) => {
        if (selectedBusiness && !savedBusiness.id) { // Editing a business that might not have an id yet in the form state
            savedBusiness.id = selectedBusiness.id;
        }

        if (selectedBusiness) {
            // Edit existing
            setBusinesses(businesses.map(b => b.id === savedBusiness.id ? savedBusiness : b));
        } else {
            // Create new
            const newBusiness = { ...savedBusiness, id: Date.now(), whatsappClicks: 0 }; // Simple ID generation
            setBusinesses([...businesses, newBusiness]);
        }
        handleBackToList();
    };

    const renderContent = () => {
        switch(viewMode) {
            case 'form':
                return <BusinessForm business={selectedBusiness} onSave={handleSave} onCancel={handleBackToList} />;
            case 'publicView':
                return selectedBusiness ? <BusinessPublicView business={selectedBusiness} onBack={handleBackToList} /> : null;
            case 'list':
            default:
                 return <BusinessList businesses={businesses} onCreate={handleCreate} onEdit={handleEdit} onViewPublic={handleViewPublic} />;
        }
    };

    const getHeaderTitle = () => {
        switch(viewMode) {
            case 'form':
                return selectedBusiness ? `Editando: ${selectedBusiness.name}` : 'Creando Nuevo Negocio';
            case 'publicView':
                 return selectedBusiness ? `Ficha Pública: ${selectedBusiness.name}` : 'Gestión de Negocios';
            case 'list':
            default:
                return 'Gestión de Negocios';
        }
    };

    const getHeaderSubtitle = () => {
        switch(viewMode) {
            case 'form':
                return 'Modificando los detalles y configuración del local.';
            case 'publicView':
                 return 'Previsualización de la información que verán los turistas.';
            case 'list':
            default:
                return 'Visualiza, crea o edita los locales comerciales.';
        }
    }


    return (
        <>
            <header>
                <h1 className="text-3xl font-bold text-white">{getHeaderTitle()}</h1>
                <p className="text-slate-400 mt-1">{getHeaderSubtitle()}</p>
            </header>
            <section className="mt-8">
                 {viewMode !== 'form' && (
                    <div className="bg-slate-800 rounded-lg shadow-lg p-6">
                        {renderContent()}
                    </div>
                )}
                {viewMode === 'form' && renderContent()}
            </section>
        </>
    );
};

export default NegociosView;

import React, { useState } from 'react';
import type { Business } from '../types';
import { PaymentStatus, Plan, Category, Sector } from '../types';

interface BusinessListProps {
    businesses: Business[];
    onEdit: (business: Business) => void;
    onCreate: () => void;
    onViewPublic: (business: Business) => void;
}

const calculateExpiryDate = (startDate: string, plan: Plan): string => {
    const start = new Date(startDate);
    if (plan === Plan.BASICO) start.setMonth(start.getMonth() + 1);
    else if (plan === Plan.PREMIUM) start.setMonth(start.getMonth() + 3);
    else if (plan === Plan.PRO) start.setFullYear(start.getFullYear() + 1);
    return start.toISOString().split('T')[0];
};

const BusinessList: React.FC<BusinessListProps> = ({ businesses, onEdit, onCreate, onViewPublic }) => {
    const [searchTerm, setSearchTerm] = useState('');
    const [filterCategory, setFilterCategory] = useState('');
    const [filterSector, setFilterSector] = useState('');
    const [filterPaymentStatus, setFilterPaymentStatus] = useState('');

    const getPlanBadgeColor = (plan: Plan) => {
        switch (plan) {
            case Plan.BASICO: return 'bg-gray-500 text-gray-100';
            case Plan.PREMIUM: return 'bg-[#2c6b8f] text-white';
            case Plan.PRO: return 'bg-[#f06c44] text-white';
            default: return 'bg-gray-500';
        }
    };

    const getPaymentStatusBadgeColor = (status: PaymentStatus) => {
        switch (status) {
            case PaymentStatus.AL_DIA: return 'bg-green-500 text-white';
            case PaymentStatus.PENDIENTE: return 'bg-red-500 text-white';
            default: return 'bg-gray-500';
        }
    };

    const filteredBusinesses = businesses.filter(business => {
        return (
            business.name.toLowerCase().includes(searchTerm.toLowerCase()) &&
            (filterCategory === '' || business.category === filterCategory) &&
            (filterSector === '' || business.sector === filterSector) &&
            (filterPaymentStatus === '' || business.paymentStatus === filterPaymentStatus)
        );
    });

    const FilterSelect: React.FC<React.SelectHTMLAttributes<HTMLSelectElement>> = (props) => (
        <select {...props} className="bg-slate-700 border border-slate-600 rounded-md p-2 text-white focus:outline-none focus:ring-2 focus:ring-[#2c6b8f] w-full sm:w-auto" />
    );

    return (
        <div>
             <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4">
                 <div className="flex flex-col sm:flex-row gap-2 w-full">
                    <input 
                        type="text"
                        placeholder="Buscar por nombre..."
                        className="bg-slate-700 border border-slate-600 rounded-md p-2 text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-[#2c6b8f] w-full sm:w-48"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                    <FilterSelect value={filterCategory} onChange={(e) => setFilterCategory(e.target.value)}>
                        <option value="">Categoría</option>
                        {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
                    </FilterSelect>
                    <FilterSelect value={filterSector} onChange={(e) => setFilterSector(e.target.value)}>
                        <option value="">Sector</option>
                        {Object.values(Sector).map(s => <option key={s} value={s}>{s}</option>)}
                    </FilterSelect>
                    <FilterSelect value={filterPaymentStatus} onChange={(e) => setFilterPaymentStatus(e.target.value)}>
                        <option value="">Estado de Pago</option>
                        {Object.values(PaymentStatus).map(ps => <option key={ps} value={ps}>{ps}</option>)}
                    </FilterSelect>
                 </div>
                 <button onClick={onCreate} className="bg-[#f06c44] text-white font-bold py-2 px-4 rounded-lg hover:bg-orange-600 transition-colors duration-200 flex items-center space-x-2 w-full md:w-auto flex-shrink-0">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M10 3a1 1 0 011 1v5h5a1 1 0 110 2h-5v5a1 1 0 11-2 0v-5H4a1 1 0 110-2h5V4a1 1 0 011-1z" clipRule="evenodd" />
                    </svg>
                    <span>Nuevo Negocio</span>
                </button>
            </div>
            <div className="overflow-x-auto">
                <table className="min-w-full text-sm text-left text-slate-300">
                    <thead className="text-xs text-slate-100 uppercase bg-[#2c6b8f]">
                        <tr>
                            <th scope="col" className="px-6 py-3">Nombre</th>
                            <th scope="col" className="px-6 py-3">Sector</th>
                            <th scope="col" className="px-6 py-3">Plan</th>
                            <th scope="col" className="px-6 py-3">Estado de Pago</th>
                            <th scope="col" className="px-6 py-3">Vencimiento</th>
                            <th scope="col" className="px-6 py-3 text-right">Acciones</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filteredBusinesses.map((business) => (
                            <tr key={business.id} className="bg-slate-800 border-b border-slate-700 hover:bg-slate-700/50">
                                <th scope="row" className="px-6 py-4 font-medium text-white whitespace-nowrap">
                                    {business.name}
                                </th>
                                <td className="px-6 py-4">{business.sector}</td>
                                <td className="px-6 py-4">
                                    <span className={`px-2 py-1 rounded-full text-xs font-semibold ${getPlanBadgeColor(business.plan)}`}>
                                        {business.plan}
                                    </span>
                                </td>
                                <td className="px-6 py-4">
                                    <span className={`px-2 py-1 rounded-full text-xs font-semibold ${getPaymentStatusBadgeColor(business.paymentStatus)}`}>
                                        {business.paymentStatus}
                                    </span>
                                </td>
                                <td className="px-6 py-4">
                                    {new Date(calculateExpiryDate(business.paymentDate, business.plan)).toLocaleDateString('es-CL', { year: 'numeric', month: 'long', day: 'numeric' })}
                                </td>
                                <td className="px-6 py-4 text-right space-x-4">
                                    <button onClick={() => onViewPublic(business)} className="font-medium text-emerald-400 hover:underline">
                                        Ver Ficha
                                    </button>
                                    <button onClick={() => onEdit(business)} className="font-medium text-[#2c6b8f] hover:underline">
                                        Editar
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

